WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/18.0/connection.js")} 
sforce.connection.query("SELECT Id,Request_Status__c FROM project_request_os__c where Id= '{!project_request_os__c.Id}'",{onSuccess: handleSuccess,onFailure: handleFailure}); 
function handleSuccess(queryresult) 
{ 
try 
{ 
records = queryresult.getArray("records"); 
records[0].Id='{!project_request_os__c.Id}'; 
records[0].Request_Status__c ='Submitted'; 
var uprec = sforce.connection.update(records); 
if (uprec[0].getBoolean("success")) 
{ 
window.location.reload(); 
} 
else 
{ 
alert(uprec[0]); 
} 
} 
catch(error) 
{ 
alert(error); 
} 
} 
function handleFailure(error) 
{ 
alert(error); 
}
